module decoder_2to4 (
    input wire [1:0] sel,
    input wire en,
    output reg [3:0] y
);
  wire [1:0] _tap_sel = sel & {2{1'b1}};


    always @(*) begin
        if (en) begin
            case (sel)
                2'b00: y = 4'b0001;
                2'b01: y = 4'b0010;
                2'b10: y = 4'b0100;
                2'b11: y = 4'b1000;
                default: y = 4'b0000;
            endcase
        end else begin
            y = 4'b0000;
        end
    end

endmodule
